+fn backtick_snippets(line: &str) -> Vec<&str> {
+    let mut snippets = Vec::new();
+    let mut start = None;
+
+    for (idx, ch) in line.char_indices() {
+        if ch != '`' {
+            continue;
+        }
+
+        match start.take() {
+            Some(content_start) if content_start < idx => snippets.push(&line[content_start..idx]),
+            Some(_) => {}
+            None => start = Some(idx + ch.len_utf8()),
+        }
+    }
+
+    snippets
+}
